
'''This script transformes files generated by robots measurement as time series, it takes into
 account one argument corresponding to PATH where robot measurement files are stored. You have also
to set up the MODEL constant accordingly to the MODEL used by graphllm.py'''

import sys
import os
import glob
from datetime import datetime,date
import pandas as pd

MODEL="vertex_ai/gemini-2.0-flash"
#MODEL='openai/gpt-4.1-mini'
#MODEL='vertex_ai/claude3.7-sonnet'
#MODEL='openai/o1-preview'
#MODEL='openai/o3'
#MODEL='openai/gpt-4.1-nano'
#MODEL='openai/gpt-4.1'
#MODEL='vertex_ai/gemini-1.5-flash'
#MODEL='openai/o4-mini'
#MODEL='openai/gpt-4o'
#MODEL='vertex_ai/gemini-1.5'
#MODEL="openai/gpt-4o-mini"
